                          <tr>\r\n                                <th>Ubicación</th>\r\n                                <th class=\"text-end\">Stock</th>\r\n                            </tr>\r\n                            </thead>\r\n                            <tbody>\r\n                            <tr v-for=\"row in form.warehouses\">\r\n                                <th>{{ row.warehouse_description }}</th>\r\n                                <th class=\"text-end\">{{ row.stock }}</th>\r\n                            </tr>\r\n                            </tbody>\r\n                        </table>\r\n                    </div>-->\r\n                        </div>\r\n                        <div class=\"row\">\r\n                            <div class=\"col-md-12\">\r\n                                <h6 class=\"separator-title\">\r\n                                    Campos adicionales\r\n                                </h6>\r\n                            </div>\r\n                            <div class=\"row col-md-12\">\r\n                                <div class=\"col-md-3\">\r\n                                    <div class=\"form-group\">\r\n                                        <label class=\"control-label\">Imágen\r\n                                            <span class=\"text-danger\"></span></label>\r\n                                        <el-upload class=\"avatar-uploader\" :data=\"{ type: 'items' }\" :headers=\"headers\"\r\n                                            :action=\"`/${resource}/uploads`\" :show-file-list=\"false\"\r\n                                            :on-success=\"onSuccess\">\r\n                                            <img v-if=\"form.image_url\" :src=\"form.image_url\" class=\"avatar\" />\r\n                                            <i v-else class=\"el-icon-plus avatar-uploader-icon\"></i>\r\n                                        </el-upload>\r\n                                    </div>\r\n                                </div>\r\n\r\n                                <div class=\"col-md-9\">\r\n                                    <div class=\"row\">\r\n                                        <div class=\"col-md-6\">\r\n                                            <div class=\"form-group\" :class=\"{\r\n                                                'has-danger':\r\n                                                    errors.brand_id\r\n                                            }\">\r\n                                                <label class=\"control-label\">\r\n                                                    Marca\r\n                                                </label>\r\n\r\n                                                <a href=\"#\" v-if=\"\r\n                                                    form_brand.add == false\r\n                                                \" class=\"control-label font-weight-bold text-info\"\r\n                                                    @click=\"form_brand.add = true\">\r\n                                                    [ + Nuevo]</a>\r\n                                                <a href=\"#\" v-if=\"\r\n                                                    form_brand.add == true\r\n                                                \" class=\"control-label font-weight-bold text-info\"\r\n                                                    @click=\"saveBrand()\">\r\n                                                    [ + Guardar]</a>\r\n                                                <a href=\"#\" v-if=\"\r\n                                                    form_brand.add == true\r\n                                                \" class=\"control-label font-weight-bold text-danger\"\r\n                                                    @click=\"form_brand.add = false\">\r\n                                                    [ Cancelar]</a>\r\n                                                <el-input v-if=\"\r\n                                                    form_brand.add == true\r\n                                                \" v-model=\"form_brand.name\" dusk=\"item_code\"\r\n                                                    style=\"margin-bottom:1.5%;\">\r\n                                                    <i slot=\"prefix\" class=\"el-icon-edit-outline\"></i></el-input>\r\n\r\n                                                <el-select v-if=\"\r\n                                                    form_brand.add == false\r\n                                                \" v-model=\"form.brand_id\" filterable clearable>\r\n                                                    <el-option v-for=\"option in brands\" :key=\"option.id\"\r\n                                                        :value=\"option.id\" :label=\"option.name\"></el-option>\r\n                                                </el-select>\r\n                                                <small class=\"text-danger\" v-if=\"errors.brand_id\"\r\n                                                    v-text=\"errors.brand_id[0]\"></small>\r\n                                            </div>\r\n                                        </div>\r\n                                        <div v-if=\"attribute_types.length > 0\" class=\"col-md-12\">\r\n                                            <h6 class=\"separator-title \">\r\n                                                Atributos\r\n                                                <el-tooltip class=\"item\" effect=\"dark\"\r\n                                                    content=\"Diferentes presentaciones para la venta del producto\"\r\n                                                    placement=\"top\">\r\n                                                    <i class=\"fa fa-info-circle\"></i>\r\n                                                </el-tooltip>\r\n                                                <a href=\"#\" class=\"control-label font-weight-bold text-info\"\r\n                                                    @click.prevent=\"\r\n                                                        clickAddAttribute\r\n                                                    \">[+ Agregar]</a>\r\n                                            </h6>\r\n                                        </div>\r\n                                        <div v-if=\"form.attributes.length > 0\" class=\"col-md-12\">\r\n                                            <div class=\"table-responsive\">\r\n                                                <table class=\"table\">\r\n                                                    <thead>\r\n                                                        <tr>\r\n                                                            <th>Tipo</th>\r\n                                                            <th>Descripción</th>\r\n                                                            <th></th>\r\n                                                        </tr>\r\n                                                    </thead>\r\n                                                    <tbody>\r\n                                                        <tr v-for=\"(row, index) in form.attributes\" :key=\"index\">\r\n                                                            <td>\r\n                                                                <el-select v-model=\"\r\n                                                                    row.attribute_type_id\r\n                                                                \" filterable\r\n                                                                    @change=\"changeAttributeType(index)\">\r\n                                                                    <el-option v-for=\"option in attribute_types\" :key=\"\r\n                                                                        option.id\r\n                                                                    \" :value=\"option.id\"\r\n                                                                        :label=\"option.description\">\r\n                                                                    </el-option>\r\n                                                                </el-select>\r\n                                                            </td>\r\n                                                            <td>\r\n                                                                <el-input v-model=\"\r\n                                                                    row.value\r\n                                                                \">\r\n                                                                    <i slot=\"prefix\"\r\n                                                                        class=\"el-icon-edit-outline\"></i></el-input>\r\n                                                            </td>\r\n                                                            <td>\r\n                                                                <button type=\"button\" class=\"btn btn-danger\"\r\n                                                                    @click.prevent=\"\r\n                                                                clickRemoveAttribute(\r\n                                                                    index)\"> x\r\n                                                                </button>\r\n                                                            </td>\r\n                                                        </tr>\r\n                                                    </tbody>\r\n                                                </table>\r\n                                            </div>\r\n                                        </div>\r\n                                    </div>\r\n                                </div>\r\n                            </div>\r\n                        </div>\r\n                    </el-tab-pane>\r\n                    <el-tab-pane v-if=\"form.unit_type_id != 'ZZ'\" label=\"Almacenes\">\r\n                        <div class=\"row\">\r\n                            <div class=\"col-12\">\r\n                                <h5 class=\"separator-title mt-0\">\r\n                                    Precios por almacén\r\n                                </h5>\r\n                                <table>\r\n                                    <tbody>\r\n                                        <tr v-for=\"w in form.warehouse_prices\" :key=\"w.id\">\r\n                                            <td width=\"80%\">\r\n                                                <h3>{{ w.warehouse }}</h3>\r\n                                            </td>\r\n                                            <td>\r\n                                                <el-input v-model=\"w.price\" @input=\"$forceUpdate()\"\r\n                                                    placeholder=\"Precio de almacen\">\r\n                                                </el-input>\r\n                                            </td>\r\n                                        </tr>\r\n                                    </tbody>\r\n                                </table>\r\n                            </div>\r\n                        </div>\r\n                    </el-tab-pane>\r\n                    <el-tab-pane label=\"Lista de Precios\">\r\n                        <div class=\"row\">\r\n                            <div v-show=\"form.unit_type_id != 'ZZ'\" class=\"col-md-12\">\r\n                                <h6 class=\"separator-title \">\r\n                                    Listado de precios\r\n                                    <el-tooltip class=\"item\" effect=\"dark\"\r\n                                        content=\"Aplica para realizar compra/venta en presentacion de diferentes precios y/o cantidades\"\r\n                                        placement=\"top\">\r\n                                        <i class=\"fa fa-info-circle\"></i>\r\n                                    </el-tooltip>\r\n                                    <a href=\"#\" class=\"control-label font-weight-bold text-info\" @click=\"clickAddRow\">\r\n                                        [ + Nuevo]</a>\r\n                                </h6>\r\n                            </div>\r\n\r\n                            <div v-show=\"form.unit_type_id != 'ZZ'\" class=\"col-md-12\"\r\n                                v-if=\"form.item_unit_types.length > 0\">\r\n                                <div class=\"table-responsive\">\r\n                                    <table class=\"table\">\r\n                                        <thead>\r\n                                            <tr>\r\n                                                <th class=\"text-center\">\r\n                                                    Unidad\r\n                                                </th>\r\n                                                <th class=\"text-center\">\r\n                                                    Descripción\r\n                                                </th>\r\n                                                <th width=\"13%\" class=\"text-center\">\r\n                                                    Cantidad\r\n                                                    <el-tooltip class=\"item\" effect=\"dark\"\r\n                                                        content=\"Cantidad de unidades\" placement=\"top\">\r\n                                                        <i class=\"fa fa-info-circle\"></i>\r\n                                                    </el-tooltip>\r\n                                                </th>\r\n                                                <th width=\"13%\" class=\"text-center\">\r\n                                                    Precio\r\n                                                    <br />\r\n                                                    unitario\r\n                                                </th>\r\n                                                <th width=\"13%\" class=\"text-center\">\r\n                                                    Total\r\n                                                </th>\r\n                                                <th class=\"text-center\">\r\n                                                    Almacen\r\n                                                </th>\r\n                                                <!-- <th class=\"text-center\">\r\n                                                    P. Defecto\r\n                                                </th> -->\r\n                                                <th>Max.<br />Cant.</th>\r\n                                            </tr>\r\n                                        </thead>\r\n                                        <tbody>\r\n                                            <tr v-for=\"(row,\r\n                                            index) in form.item_unit_types\" :key=\"index\">\r\n                                                <template v-if=\"row.id\">\r\n                                                    <td class=\"text-center\">\r\n                                                        {{ row.unit_type_id }}\r\n                                                    </td>\r\n                                                    <td class=\"text-center\">\r\n                                                        {{ row.description }}\r\n                                                    </td>\r\n                                                    <td class=\"text-center\">\r\n                                                        {{ row.quantity_unit }}\r\n                                                    </td>\r\n                                                    <td class=\"text-center\">\r\n                                                        <el-input v-model=\"row.price2\" @input=\"\r\n                                                            undToTotal(\r\n                                                                index,\r\n                                                                row.price2,\r\n                                                                row.quantity_unit\r\n                                                            )\r\n                                                        \">\r\n                                                            <i slot=\"prefix\"\r\n                                                                class=\"el-icon-edit-outline\"></i></el-input>\r\n                                                    </td>\r\n                                                    <td class=\"text-center\">\r\n                                                        <el-input v-model=\"row.total\" @input=\"\r\n                                                            totalToUnd(\r\n                                                                index,\r\n                                                                row.total,\r\n                                                                row.quantity_unit\r\n                                                            )\r\n                                                        \">\r\n                                                            <i slot=\"prefix\"\r\n                                                                class=\"el-icon-edit-outline\"></i></el-input>\r\n\r\n                                                        <!-- <td class=\"text-center\">\r\n                                                        Precio\r\n                                                        {{ row.price_default }}\r\n                                                    </td> -->\r\n                                                    </td>\r\n                                                    <td>\r\n                                                        <el-select clearable v-model=\"\r\n                                                            row.warehouse_id\r\n                                                        \">\r\n                                                            <el-option v-for=\"w in warehouses\" :key=\"w.id\" :value=\"w.id\"\r\n                                                                :label=\"\r\n                                                                    w.description\r\n                                                                \"></el-option>\r\n                                                        </el-select>\r\n                                                    </td>\r\n                                                    <td>\r\n                                                        <el-checkbox v-model=\"\r\n                                                            row.selected\r\n                                                        \" @change=\"\r\n    selectedMax(\r\n        index\r\n    )\r\n\"></el-checkbox>\r\n                                                    </td>\r\n\r\n                                                    <td class=\"series-table-actions text-end\">\r\n                                                        <button type=\"button\"\r\n                                                            class=\"btn waves-effect waves-light btn-sm btn-danger\"\r\n                                                            @click.prevent=\"\r\n                                                                clickDelete(\r\n                                                                    row.id\r\n                                                                )\r\n                                                            \">\r\n                                                            <i class=\"fa fa-trash\"></i>\r\n                                                        </button>\r\n                                                    </td>\r\n                                                </template>\r\n                                                <template v-else>\r\n                                                    <td>\r\n                                                        <div class=\"form-group\">\r\n                                                            <el-select v-model=\"\r\n                                                                row.unit_type_id\r\n                                                            \" dusk=\"item_unit_type.unit_type_id\">\r\n                                                                <el-option v-for=\"option in unit_types\" :key=\"\r\n                                                                    option.id\r\n                                                                \" :value=\"\r\n    option.id\r\n\" :label=\"\r\n    option.description\r\n\"></el-option>\r\n                                                            </el-select>\r\n                                                        </div>\r\n                                                    </td>\r\n                                                    <td>\r\n                                                        <div class=\"form-group\">\r\n                                                            <el-input v-model=\"\r\n                                                                row.description\r\n                                                            \">\r\n                                                                <i slot=\"prefix\"\r\n                                                                    class=\"el-icon-edit-outline\"></i></el-input>\r\n                                                        </div>\r\n                                                    </td>\r\n                                                    <td>\r\n                                                        <div class=\"form-group\">\r\n                                                            <el-input @input=\"\r\n                                                                undToTotal(\r\n                                                                    index,\r\n                                                                    row.price2,\r\n                                                                    row.quantity_unit\r\n                                                                )\r\n                                                            \" v-model=\"\r\n    row.quantity_unit\r\n\">\r\n                                                                <i slot=\"prefix\"\r\n                                                                    class=\"el-icon-edit-outline\"></i></el-input>\r\n                                                        </div>\r\n                                                    </td>\r\n                                                    <td>\r\n                                                        <div class=\"form-group\">\r\n                                                            <el-input v-model=\"\r\n                                                                row.price2\r\n                                                            \" @input=\"\r\n    undToTotal(\r\n        index,\r\n        row.price2,\r\n        row.quantity_unit\r\n    )\r\n\">\r\n                                                                <i slot=\"prefix\"\r\n                                                                    class=\"el-icon-edit-outline\"></i></el-input>\r\n                                                        </div>\r\n                                                    </td>\r\n                                                    <td>\r\n                                                        <div class=\"form-group\">\r\n                                                            <el-input v-model=\"\r\n                                                                row.total\r\n                                                            \" @input=\"\r\n    totalToUnd(\r\n        index,\r\n        row.total,\r\n        row.quantity_unit\r\n    )\r\n\">\r\n                                                                <i slot=\"prefix\"\r\n                                                                    class=\"el-icon-edit-outline\"></i></el-input>\r\n                                                        </div>\r\n                                                    </td>\r\n                                                    <td>\r\n                                                        <el-select clearable v-model=\"\r\n                                                            row.warehouse_id\r\n                                                        \">\r\n                                                            <el-option v-for=\"w in warehouses\" :key=\"w.id\" :value=\"w.id\"\r\n                                                                :label=\"\r\n                                                                    w.description\r\n                                                                \"></el-option>\r\n                                                        </el-select>\r\n                                                    </td>\r\n                                                    <td>\r\n                                                        <el-checkbox v-model=\"\r\n                                                            row.selected\r\n                                                        \" @change=\"\r\n    selectedMax(\r\n        index\r\n    )\r\n\"></el-checkbox>\r\n                                                    </td>\r\n                                                    <td class=\"series-table-actions text-end\">\r\n                                                        <button type=\"button\"\r\n                                                            class=\"btn waves-effect waves-light btn-sm btn-danger\"\r\n                                                            @click.prevent=\"\r\n                                                                clickCancel(\r\n                                                                    index\r\n                                                                )\r\n                                                            \">\r\n                                                            <i class=\"fa fa-trash\"></i>\r\n                                                        </button>\r\n                                                    </td>\r\n                                                </template>\r\n                                            </tr>\r\n                                        </tbody>\r\n                                    </table>\r\n                                </div>\r\n                            </div>\r\n                        </div>\r\n                    </el-tab-pane>\r\n\r\n                    <!-- <el-tab-pane label=\"Atributos\">\r\n                        <div class=\"row\">\r\n                            <div class=\"col-md-12\">\r\n                                <h6 class=\"separator-title\">\r\n                                    Campos adicionales\r\n                                </h6>\r\n                            </div>\r\n                            <div class=\"row col-md-12\">\r\n                                <div class=\"col-md-3\">\r\n                                    <div class=\"form-group\">\r\n                                        <label class=\"control-label\">Imágen\r\n                                            <span class=\"text-danger\"></span></label>\r\n                                        <el-upload class=\"avatar-uploader\" :data=\"{ type: 'items' }\" :headers=\"headers\"\r\n                                            :action=\"`/${resource}/uploads`\" :show-file-list=\"false\"\r\n                                            :on-success=\"onSuccess\">\r\n                                            <img v-if=\"form.image_url\" :src=\"form.image_url\" class=\"avatar\" />\r\n                                            <i v-else class=\"el-icon-plus avatar-uploader-icon\"></i>\r\n                                        </el-upload>\r\n                                    </div>\r\n                                </div>\r\n\r\n                                <div class=\"col-md-9\">\r\n                                    <div class=\"row\">\r\n                                        <div class=\"col-md-6\">\r\n                                            <div class=\"form-group\" :class=\"{\r\n                                                'has-danger':\r\n                                                    errors.brand_id\r\n                                            }\">\r\n                                                <label class=\"control-label\">\r\n                                                    Marca\r\n                                                </label>\r\n\r\n                                                <a href=\"#\" v-if=\"\r\n                                                    form_brand.add == false\r\n                                                \" class=\"control-label font-weight-bold text-info\" @click=\"    form_brand.add = true\">\r\n                                                    [ + Nuevo]</a>\r\n                                                <a href=\"#\" v-if=\"\r\n                                                    form_brand.add == true\r\n                                                \" class=\"control-label font-weight-bold text-info\"\r\n                                                    @click=\"saveBrand()\">\r\n                                                    [ + Guardar]</a>\r\n                                                <a href=\"#\" v-if=\"\r\n                                                    form_brand.add == true\r\n                                                \" class=\"control-label font-weight-bold text-danger\" @click=\"    form_brand.add = false\">\r\n                                                    [ Cancelar]</a>\r\n                                                <el-input v-if=\"\r\n                                                    form_brand.add == true\r\n                                                \" v-model=\"form_brand.name\" dusk=\"item_code\"\r\n                                                    style=\"margin-bottom:1.5%;\">\r\n                                                    <i slot=\"prefix\" class=\"el-icon-edit-outline\"></i></el-input>\r\n\r\n                                                <el-select v-if=\"\r\n                                                    form_brand.add == false\r\n                                                \" v-model=\"form.brand_id\" filterable clearable>\r\n                                                    <el-option v-for=\"option in brands\" :key=\"option.id\"\r\n                                                        :value=\"option.id\" :label=\"option.name\"></el-option>\r\n                                                </el-select>\r\n                                                <small class=\"text-danger\" v-if=\"errors.brand_id\"\r\n                                                    v-text=\"errors.brand_id[0]\"></small>\r\n                                            </div>\r\n                                        </div>\r\n                                        <div v-if=\"attribute_types.length > 0\" class=\"col-md-12\">\r\n                                            <h6 class=\"separator-title \">\r\n                                                Atributos\r\n                                                <el-tooltip class=\"item\" effect=\"dark\"\r\n                                                    content=\"Diferentes presentaciones para la venta del producto\"\r\n                                                    placement=\"top\">\r\n                                                    <i class=\"fa fa-info-circle\"></i>\r\n                                                </el-tooltip>\r\n                                                <a href=\"#\" class=\"control-label font-weight-bold text-info\"\r\n                                                    @click.prevent=\"\r\n                                                        clickAddAttribute\r\n                                                    \">[+ Agregar]</a>\r\n                                            </h6>\r\n                                        </div>\r\n                                        <div v-if=\"form.attributes.length > 0\" class=\"col-md-12\">\r\n                                            <div class=\"table-responsive\">\r\n                                                <table class=\"table\">\r\n                                                    <thead>\r\n                                                        <tr>\r\n                                                            <th>Tipo</th>\r\n                                                            <th>Descripción</th>\r\n                                                            <th></th>\r\n                                                        </tr>\r\n                                                    </thead>\r\n                                                    <tbody>\r\n                                                        <tr v-for=\"(row, index) in form.attributes\" :key=\"index\">\r\n                                                            <td>\r\n                                                                <el-select v-model=\"\r\n                                                                    row.attribute_type_id\r\n                                                                \" filterable @change=\"    changeAttributeType(        index    )\">\r\n                                                                    <el-option v-for=\"option in attribute_types\" :key=\"\r\n                                                                        option.id\r\n                                                                    \" :value=\"    option.id\" :label=\"    option.description\">\r\n                                                                    </el-option>\r\n                                                                </el-select>\r\n                                                            </td>\r\n                                                            <td>\r\n                                                                <el-input v-model=\"\r\n                                                                    row.value\r\n                                                                \">\r\n                                                                    <i slot=\"prefix\"\r\n                                                                        class=\"el-icon-edit-outline\"></i></el-input>\r\n                                                            </td>\r\n                                                            <td>\r\n                                                                <button type=\"button\" class=\"btn btn-danger\"\r\n                                                                    @click.prevent=\"\r\n                                                                        clickRemoveAttribute(\r\n                                                                            index       ) \">   x\r\n                                                                </button>\r\n                                                            </td>\r\n                                                        </tr>\r\n                                                    </tbody>\r\n                                                </table>\r\n                                            </div>\r\n                                        </div>\r\n                                    </div>\r\n                                </div>\r\n                            </div>\r\n                        </div>\r\n                    </el-tab-pane> -->\r\n                    <el-tab-pane label=\"Compras\">\r\n                        <div class=\"row\">\r\n                            <div class=\"short-div col-md-8\">\r\n                                <div class=\"form-group\" :class=\"{\r\n                                    'has-danger':\r\n                                        errors.purchase_affectation_igv_type_id\r\n                                }\">\r\n                                    <label class=\"control-label\">Tipo de afectación (Compra)</label>\r\n                                    <el-select v-model=\"\r\n                                        form.purchase_affectation_igv_type_id\r\n                                    \">\r\n                                        <el-option v-for=\"option in affectation_igv_types\" :key=\"option.id\"\r\n                                            :value=\"option.id\" :label=\"option.description\"></el-option>\r\n                                    </el-select>\r\n                                    <small class=\"text-danger\" v-if=\"\r\n                                        errors.purchase_affectation_igv_type_id\r\n                                    \" v-text=\"\r\n    errors\r\n        .purchase_affectation_igv_type_id[0]\r\n\"></small>\r\n                                </div>\r\n                            </div>\r\n\r\n                            <div class=\"short-div col-md-4\">\r\n                                <div class=\"form-group\" :class=\"{\r\n                                    'has-danger': errors.purchase_unit_price\r\n                                }\">\r\n                                    <label class=\"control-label\">Precio Unitario (Compra)</label>\r\n                                    <el-input v-model=\"form.purchase_unit_price\" dusk=\"purchase_unit_price\" @input=\"\r\n                                        calculatePercentageOfProfitByPurchase\r\n                                    \">\r\n                                        <i slot=\"prefix\" class=\"el-icon-edit-outline\"></i></el-input>\r\n                                    <small class=\"text-danger\" v-if=\"errors.purchase_unit_price\"\r\n                                        v-text=\"errors.purchase_unit_price[0]\"></small>\r\n                                </div>\r\n                            </div>\r\n                            <div class=\"short-div col-md-4\">\r\n                                <div class=\"form-group\" :class=\"{\r\n                                    'has-danger':\r\n                                        errors.percentage_of_profit\r\n                                }\">\r\n                                    <label class=\"control-label\">\r\n                                        <el-checkbox v-model=\"\r\n                                            enabled_percentage_of_profit\r\n                                        \" @change=\"\r\n    changeEnabledPercentageOfProfit\r\n\"></el-checkbox>\r\n                                        Porcentaje de ganancia (%)\r\n                                    </label>\r\n                                    <el-input v-model=\"form.percentage_of_profit\" :disabled=\"\r\n                                        !enabled_percentage_of_profit\r\n                                    \" @input=\"\r\n    calculatePercentageOfProfitByPercentage\r\n\">\r\n                                        <i slot=\"prefix\" class=\"el-icon-edit-outline\"></i></el-input>\r\n                                    <small class=\"text-danger\" v-if=\"errors.percentage_of_profit\"\r\n                                        v-text=\"errors.percentage_of_profit[0]\"></small>\r\n                                </div>\r\n                            </div>\r\n                        </div>\r\n                    </el-tab-pane>\r\n                </el-tabs>\r\n            </div>\r\n            <div class=\"form-actions text-end pt-2 pb-2\">\r\n                <el-button @click.prevent=\"close()\">Cancelar</el-button>\r\n                <el-button type=\"primary\" native-type=\"submit\" :loading=\"loading_submit\">Guardar</el-button>\r\n            </div>\r\n        </form>\r\n        <!-- <percentage-perception\r\n                :showDialog.sync=\"showPercentagePerception\"\r\n                :percentage_perception=\"percentage_perception\">\r\n        </percentage-perception> -->\r\n\r\n        <lots-form :showDialog.sync=\"showDialogLots\" :stock=\"form.stock\" :recordId=\"recordId\" :lots=\"form.lots\"\r\n            @addRowLot=\"addRowLot\">\r\n        </lots-form>\r\n    </el-dialog>\r\n</template>\r\n\r\n<script>\r\n// import PercentagePerception from './partials/percentage_perception.vue'\r\nimport LotsForm from \"./partials/lots.vue\";\r\n\r\nexport default {\r\n    props: [\"showDialog\", \"recordId\", \"external\"],\r\n    components: { LotsForm },\r\n\r\n    data() {\r\n        return {\r\n            showDialogLots: false,\r\n            form_category: { add: false, name: null, id: null },\r\n            form_brand: { add: false, name: null, id: null },\r\n            warehouses: [],\r\n            loading_submit: false,\r\n            showPercentagePerception: false,\r\n            has_percentage_perception: false,\r\n            percentage_perception: null,\r\n            enabled_percentage_of_profit: false,\r\n            titleDialog: null,\r\n            resource: \"items\",\r\n            errors: {},\r\n            headers: headers_token,\r\n            form: {},\r\n            configuration: {},\r\n            unit_types: [],\r\n            areas: [],\r\n            currency_types: [],\r\n            system_isc_types: [],\r\n            affectation_igv_types: [],\r\n            categories: [],\r\n            brands: [],\r\n            accounts: [],\r\n            show_has_igv: true,\r\n            have_account: false,\r\n            showSeries: false,\r\n            item_unit_type: {\r\n                id: null,\r\n                unit_type_id: null,\r\n                quantity_unit: 0,\r\n                price1: 0,\r\n                price2: 0,\r\n                price3: 0,\r\n                price_default: 2\r\n            },\r\n            attribute_types: [],\r\n            area_id : 2 \r\n        };\r\n    },\r\n    async created() {\r\n       \r\n\r\n        await this.initForm();        \r\n        await this.$http.get(`/${this.resource}/tables`).then(response => {\r\n          \r\n\r\n            this.unit_types = response.data.unit_types;\r\n            this.accounts = response.data.accounts;\r\n            this.currency_types = response.data.currency_types;\r\n            this.system_isc_types = response.data.system_isc_types;\r\n            this.affectation_igv_types = response.data.affectation_igv_types;\r\n            this.warehouses = response.data.warehouses;\r\n            if (this.warehouses.length > 0) {\r\n                this.form.warehouse_id = this.warehouses[0].id;\r\n                this.form.warehouse_prices = this.warehouses.map(w => ({\r\n                    id: null,\r\n                    item_id: null,\r\n                    warehouse_id: w.id,\r\n                    price: null,\r\n                    warehouse: w.description\r\n                }));\r\n            }\r\n            this.categories = response.data.categories;\r\n            this.brands = response.data.brands;\r\n            this.attribute_types = response.data.attribute_types;\r\n            this.configuration = response.data.configuration;\r\n            this.areas = response.data.areas;\r\n            this.form.sale_affectation_igv_type_id =\r\n                this.affectation_igv_types.length > 0\r\n                    ? this.affectation_igv_types[0].id\r\n                    : null;\r\n            this.form.purchase_affectation_igv_type_id =\r\n                this.affectation_igv_types.length > 0\r\n                    ? this.affectation_igv_types[0].id\r\n                    : null;\r\n            //agregar opciones para entorno restaurante \r\n\r\n        });\r\n\r\n        this.$eventHub.$on(\"submitPercentagePerception\", data => {\r\n            this.form.percentage_perception = data;\r\n            if (!this.form.percentage_perception)\r\n                this.has_percentage_perception = false;\r\n        });\r\n\r\n        this.$eventHub.$on(\"reloadTables\", () => {\r\n            this.reloadTables();\r\n        });\r\n\r\n\r\n        await this.setDefaultConfiguration();\r\n    },\r\n\r\n    methods: {\r\n        selectedMax(idx) {\r\n            let selected = this.form.item_unit_types[idx].selected;\r\n            for (let i = 0; i < this.form.item_unit_types.length; i++) {\r\n                let it = this.form.item_unit_types[i];\r\n                it.selected = false;\r\n            }\r\n\r\n            this.form.item_unit_types[idx].selected = selected;\r\n            if (selected) {\r\n                let qty = Number(this.form.item_unit_types[idx].quantity_unit);\r\n                !isNaN(qty) && (this.form.max_quantity = qty);\r\n            } else {\r\n                this.form.max_quantity = null;\r\n            }\r\n            this.$forceUpdate();\r\n        },\r\n        undToTotal(idx, amount, qty) {\r\n            let arr = this.form.item_unit_types;\r\n            if (qty > 0) {\r\n                arr[idx].total = Number(amount) * Number(qty);\r\n            } else {\r\n                this.$toast.warning(\"Ingrese una cantidad válida\");\r\n                arr[idx].price2 = 0;\r\n            }\r\n        },\r\n        