                    >\r\n                                    <el-input\r\n                                        v-model=\"form.description\"\r\n                                        dusk=\"description\"\r\n                                    >\r\n                                        <i\r\n                                            slot=\"prefix\"\r\n                                            class=\"el-icon-edit-outline\"\r\n                                        ></i>\r\n                                    </el-input>\r\n                                    <small\r\n                                        class=\"text-danger\"\r\n                                        v-if=\"errors.description\"\r\n                                        v-text=\"errors.description[0]\"\r\n                                    ></small>\r\n                                </div>\r\n                            </div>\r\n                            <div class=\"col-md-3\">\r\n                                <div\r\n                                    class=\"form-group\"\r\n                                    :class=\"{\r\n                                        'has-danger': errors.second_name\r\n                                    }\"\r\n                                >\r\n                                    <label class=\"control-label\"\r\n                                        >Nombre secundario\r\n                                    </label>\r\n                                    <el-input\r\n                                        v-model=\"form.second_name\"\r\n                                        dusk=\"second_name\"\r\n                                    >\r\n                                        <i\r\n                                            slot=\"prefix\"\r\n                                            class=\"el-icon-edit-outline\"\r\n                                        ></i\r\n                                    ></el-input>\r\n                                    <small\r\n                                        class=\"text-danger\"\r\n                                        v-if=\"errors.second_name\"\r\n                                        v-text=\"errors.second_name[0]\"\r\n                                    ></small>\r\n                                </div>\r\n                            </div>\r\n                            <div class=\"col-md-3\">\r\n                                <div\r\n                                    class=\"form-group\"\r\n                                    :class=\"{\r\n                                        'has-danger': errors.category_id\r\n                                    }\"\r\n                                >\r\n                                    <label class=\"control-label\">\r\n                                        Categoría\r\n                                    </label>\r\n\r\n                                    <a\r\n                                        href=\"#\"\r\n                                        v-if=\"form_category.add == false\"\r\n                                        class=\"control-label font-weight-bold text-info\"\r\n                                        @click=\"form_category.add = true\"\r\n                                    >\r\n                                        [ + Nuevo]</a\r\n                                    >\r\n                                    <a\r\n                                        href=\"#\"\r\n                                        v-if=\"form_category.add == true\"\r\n                                        class=\"control-label font-weight-bold text-info\"\r\n                                        @click=\"saveCategory()\"\r\n                                    >\r\n                                        [ + Guardar]</a\r\n                                    >\r\n                                    <a\r\n                                        href=\"#\"\r\n                                        v-if=\"form_category.add == true\"\r\n                                        class=\"control-label font-weight-bold text-danger\"\r\n                                        @click=\"form_category.add = false\"\r\n                                    >\r\n                                        [ Cancelar]</a\r\n                                    >\r\n                                    <el-input\r\n                                        v-if=\"form_category.add == true\"\r\n                                        v-model=\"form_category.name\"\r\n                                        dusk=\"item_code\"\r\n                                        style=\"margin-bottom:1.5%;\"\r\n                                    >\r\n                                        <i\r\n                                            slot=\"prefix\"\r\n                                            class=\"el-icon-edit-outline\"\r\n                                        ></i\r\n                                    ></el-input>\r\n\r\n                                    <el-select\r\n                                        v-if=\"form_category.add == false\"\r\n                                        v-model=\"form.category_id\"\r\n                                        filterable\r\n                                        clearable\r\n                                    >\r\n                                        <el-option\r\n                                            v-for=\"option in categories\"\r\n                                            :key=\"option.id\"\r\n                                            :value=\"option.id\"\r\n                                            :label=\"option.name\"\r\n                                        ></el-option>\r\n                                    </el-select>\r\n                                    <small\r\n                                        class=\"text-danger\"\r\n                                        v-if=\"errors.category_id\"\r\n                                        v-text=\"errors.category_id[0]\"\r\n                                    ></small>\r\n                                </div>\r\n                            </div>\r\n                            <div class=\"col-md-3\">\r\n                                <div\r\n                                    class=\"form-group\"\r\n                                    :class=\"{\r\n                                        'has-danger':\r\n                                            errors.sale_affectation_igv_type_id\r\n                                    }\"\r\n                                >\r\n                                    <label class=\"control-label\"\r\n                                        >Zona\r\n                                        <el-tooltip\r\n                                            class=\"item\"\r\n                                            effect=\"dark\"\r\n                                            content=\"Lugar en donde se despacha el producto\"\r\n                                            placement=\"top-start\"\r\n                                        >\r\n                                            <i class=\"fa fa-info-circle\"></i>\r\n                                        </el-tooltip>\r\n                                    </label>\r\n                                    <el-select v-model=\"form.area_id\">\r\n                                        <el-option\r\n                                            v-for=\"option in areas\"\r\n                                            :key=\"option.id\"\r\n                                            :value=\"option.id\"\r\n                                            :label=\"option.description\"\r\n                                        ></el-option>\r\n                                    </el-select>\r\n                                    <small\r\n                                        class=\"form-control-feedback\"\r\n                                        v-if=\"\r\n                                            errors.sale_affectation_igv_type_id\r\n                                        \"\r\n                                        v-text=\"\r\n                                            errors\r\n                                                .sale_affectation_igv_type_id[0]\r\n                                        \"\r\n                                    >\r\n                                    </small>\r\n                                </div>\r\n                            </div>\r\n                            <div\r\n                                class=\"col-md-3 center-el-checkbox\"\r\n                                v-show=\"show_has_igv\"\r\n                            >\r\n                                <div\r\n                                    class=\"form-group\"\r\n                                    :class=\"{ 'has-danger': errors.has_igv }\"\r\n                                >\r\n                                    <el-checkbox v-model=\"form.has_igv\"\r\n                                        >Incluye Igv\r\n                                        {{\r\n                                            configuration.include_igv\r\n                                        }}</el-checkbox\r\n                                    ><br />\r\n                                    <small\r\n                                        class=\"text-danger\"\r\n                                        v-if=\"errors.has_igv\"\r\n                                        v-text=\"errors.has_igv[0]\"\r\n                                    ></small>\r\n                                </div>\r\n                            </div>\r\n                            <!-- <div v-show=\"form.unit_type_id !='ZZ'\" class=\"col-md-3 center-el-checkbox\">\r\n                                <div class=\"form-group\" :class=\"{'has-danger': errors.calculate_quantity}\">\r\n                                    <el-checkbox v-model=\"form.calculate_quantity\">Calcular cantidad por precio</el-checkbox><br>\r\n                                    <small class=\"text-danger\" v-if=\"errors.calculate_quantity\" v-text=\"errors.calculate_quantity[0]\"></small>\r\n                                </div>\r\n                            </div> -->\r\n\r\n                            <div class=\"col-md-3\">\r\n                                <div\r\n                                    class=\"form-group\"\r\n                                    :class=\"{ 'has-danger': errors.location }\"\r\n                                >\r\n                                    <label class=\"control-label\"\r\n                                        >Ubicación del producto\r\n                                    </label>\r\n                                    <el-input\r\n                                        v-model=\"form.location\"\r\n                                        dusk=\"name\"\r\n                                    ></el-input>\r\n                                    <small\r\n                                        class=\"text-danger\"\r\n                                        v-if=\"errors.location\"\r\n                                        v-text=\"errors.location[0]\"\r\n                                    ></small>\r\n                                </div>\r\n                            </div>\r\n\r\n                            <div class=\"col-md-3\">\r\n                                <div\r\n                                    class=\"form-group\"\r\n                                    :class=\"{\r\n                                        'has-danger': errors.unit_type_id\r\n                                    }\"\r\n                                >\r\n                                    <label class=\"control-label\">Unidad</label>\r\n                                    <el-select\r\n                                        v-model=\"form.unit_type_id\"\r\n                                        dusk=\"unit_type_id\"\r\n                                    >\r\n                                        <el-option\r\n                                            v-for=\"option in unit_types\"\r\n                                            :key=\"option.id\"\r\n                                            :value=\"option.id\"\r\n                                            :label=\"option.description\"\r\n                                        ></el-option>\r\n                                    </el-select>\r\n                                    <small\r\n                                        class=\"text-danger\"\r\n                                        v-if=\"errors.unit_type_id\"\r\n                                        v-text=\"errors.unit_type_id[0]\"\r\n                                    ></small>\r\n                                </div>\r\n                            </div>\r\n                            <div class=\"col-md-3\">\r\n                                <div\r\n                                    class=\"form-group\"\r\n                                    :class=\"{\r\n                                        'has-danger': errors.currency_type_id\r\n                                    }\"\r\n                                >\r\n                                    <label class=\"control-label\">Moneda</label>\r\n                                    <el-select\r\n                                        v-model=\"form.currency_type_id\"\r\n                                        dusk=\"currency_type_id\"\r\n                                    >\r\n                                        <el-option\r\n                                            v-for=\"option in currency_types\"\r\n                                            :key=\"option.id\"\r\n                                            :value=\"option.id\"\r\n                                            :label=\"option.description\"\r\n                                        ></el-option>\r\n                                    </el-select>\r\n                                    <small\r\n                                        class=\"text-danger\"\r\n                                        v-if=\"errors.currency_type_id\"\r\n                                        v-text=\"errors.currency_type_id[0]\"\r\n                                    ></small>\r\n                                </div>\r\n                            </div>\r\n                            <div class=\"col-md-3\">\r\n                                <div\r\n                                    class=\"form-group\"\r\n                                    :class=\"{\r\n                                        'has-danger': errors.sale_unit_price\r\n                                    }\"\r\n                                >\r\n                                    <label class=\"control-label\"\r\n                                        >Precio Unitario (Venta)\r\n                                        <span class=\"text-danger\"\r\n                                            >*</span\r\n                                        ></label\r\n                                    >\r\n                                    <el-input\r\n                                        v-model=\"form.sale_unit_price\"\r\n                                        dusk=\"sale_unit_price\"\r\n                                        @input=\"\r\n                                            calculatePercentageOfProfitBySale\r\n                                        \"\r\n                                    >\r\n                                        <i\r\n                                            slot=\"prefix\"\r\n                                            class=\"el-icon-edit-outline\"\r\n                                        ></i\r\n                                    ></el-input>\r\n                                    <small\r\n                                        class=\"text-danger\"\r\n                                        v-if=\"errors.sale_unit_price\"\r\n                                        v-text=\"errors.sale_unit_price[0]\"\r\n                                    ></small>\r\n                                </div>\r\n                            </div>\r\n\r\n                            <div class=\"col-md-3\">\r\n                                <div\r\n                                    class=\"form-group\"\r\n                                    :class=\"{\r\n                                        'has-danger':\r\n                                            errors.sale_affectation_igv_type_id\r\n                                    }\"\r\n                                >\r\n                                    <label class=\"control-label\"\r\n                                        >Tipo de afectación (Venta)</label\r\n                                    >\r\n                                    <el-select\r\n                                        v-model=\"\r\n                                            form.sale_affectation_igv_type_id\r\n                                        \"\r\n                                        @change=\"changeAffectationIgvType\"\r\n                                    >\r\n                                        <el-option\r\n                                            v-for=\"option in affectation_igv_types\"\r\n                                            :key=\"option.id\"\r\n                                            :value=\"option.id\"\r\n                                            :label=\"option.description\"\r\n                                        ></el-option>\r\n                                    </el-select>\r\n                                    <small\r\n                                        class=\"text-danger\"\r\n                                        v-if=\"\r\n                                            errors.sale_affectation_igv_type_id\r\n                                        \"\r\n                                        v-text=\"\r\n                                            errors\r\n                                                .sale_affectation_igv_type_id[0]\r\n                                        \"\r\n                                    ></small>\r\n                                </div>\r\n                            </div>\r\n\r\n                            <div\r\n                                class=\"col-md-3\"\r\n                                v-show=\"\r\n                                    recordId == null &&\r\n                                        form.unit_type_id != 'ZZ'\r\n                                \"\r\n                            >\r\n                                <div\r\n                                    class=\"form-group\"\r\n                                    :class=\"{ 'has-danger': errors.stock }\"\r\n                                >\r\n                                    <label\r\n                                        v-if=\"!allEstablishment\"\r\n                                        class=\"control-label\"\r\n                                        >Stock Inicial</label\r\n                                    >\r\n                                    <label v-else class=\"control-label\">\r\n                                        Stock Inicial en cada establecimiento\r\n                                    </label>\r\n                                    <el-input v-model=\"form.stock\">\r\n                                        <i\r\n                                            slot=\"prefix\"\r\n                                            class=\"el-icon-edit-outline\"\r\n                                        ></i\r\n                                    ></el-input>\r\n                                    <small\r\n                                        class=\"text-danger\"\r\n                                        v-if=\"errors.stock\"\r\n                                        v-text=\"errors.stock[0]\"\r\n                                    ></small>\r\n                                </div>\r\n                            </div>\r\n                            <!-- <div class=\"col-md-3\">\r\n                        <div class=\"form-group\" :class=\"{'has-danger': errors.barcode}\">\r\n                            <label class=\"control-label\">Código Barra\r\n                                <el-tooltip class=\"item\" effect=\"dark\" content=\"Código Barra de la empresa para el control de sus productos\" placement=\"top-start\">\r\n                                    <i class=\"fa fa-info-circle\"></i>\r\n                                </el-tooltip>\r\n                            </label>\r\n                            <el-input v-model=\"form.barcode\" dusk=\"barcode\"> <i slot=\"prefix\" class=\"el-icon-edit-outline\"></i></el-input>\r\n                            <small class=\"text-danger\" v-if=\"errors.barcode\" v-text=\"errors.barcode[0]\"></small>\r\n                        </div>\r\n                    </div> -->\r\n                            <!-- <div class=\"col-md-3\">\r\n                        <div class=\"form-group\" :class=\"{'has-danger': errors.item_code}\">\r\n                            <label class=\"control-label\">Código Sunat\r\n                                <el-tooltip class=\"item\" effect=\"dark\" content=\"Código proporcionado por SUNAT, campo obligatorio para exportaciones\" placement=\"top\">\r\n                                    <i class=\"fa fa-info-circle\"></i>\r\n                                </el-tooltip>\r\n                            </label>\r\n                            <el-input v-model=\"form.item_code\" dusk=\"item_code\"> <i slot=\"prefix\" class=\"el-icon-edit-outline\"></i></el-input>\r\n                            <small class=\"text-danger\" v-if=\"errors.item_code\" v-text=\"errors.item_code[0]\"></small>\r\n                        </div>\r\n                    </div>\r\n                 \r\n\r\n                    <div class=\"col-md-3\" v-show=\"form.unit_type_id !='ZZ'\">\r\n                        <div class=\"form-group\" :class=\"{'has-danger': errors.stock_min}\">\r\n                            <label class=\"control-label\">Stock Mínimo</label>\r\n                            <el-input v-model=\"form.stock_min\"> <i slot=\"prefix\" class=\"el-icon-edit-outline\"></i></el-input>\r\n                            <small class=\"text-danger\" v-if=\"errors.stock_min\" v-text=\"errors.stock_min[0]\"></small>\r\n                        </div>\r\n                    </div>-->\r\n\r\n                            <div\r\n                                class=\"col-md-3\"\r\n                                v-show=\"recordId == null\"\r\n                                v-if=\"form.unit_type_id != 'ZZ'\"\r\n                            >\r\n                                <div\r\n                                    class=\"form-group\"\r\n                                    :class=\"{\r\n                                        'has-danger': errors.warehouse_id\r\n                                    }\"\r\n                                >\r\n                                    <label class=\"control-label\">\r\n                                        Almacén\r\n                                        <el-tooltip\r\n                                            class=\"item\"\r\n                                            effect=\"dark\"\r\n                                            content=\"Si no selecciona almacén, se asignará por defecto el relacionado al establecimiento\"\r\n                                            placement=\"top\"\r\n                                        >\r\n                                            <i class=\"fa fa-info-circle\"></i>\r\n                                        </el-tooltip>\r\n                                    </label>\r\n                                    <el-select\r\n                                        :disabled=\"allEstablishment\"\r\n                                        @change=\"changeWarehouse\"\r\n                                        v-model=\"form.warehouse_id\"\r\n                                    >\r\n                                        <el-option\r\n                                            v-for=\"option in warehouses\"\r\n                                            :key=\"option.id\"\r\n                                            :value=\"option.id\"\r\n                                            :label=\"option.description\"\r\n                                        ></el-option>\r\n                                    </el-select>\r\n                                    <small v-if=\"!recordId\">\r\n                                        <el-checkbox v-model=\"allEstablishment\">\r\n                                            Enviar a todos los almacenes\r\n                                        </el-checkbox>\r\n                                    </small>\r\n                                    <!-- <small class=\"text-danger\" v-if=\"errors.warehouse_id\"\r\n                                        v-text=\"errors.warehouse_id[0]\"></small> -->\r\n                                </div>\r\n                            </div>\r\n\r\n                            <div\r\n                                class=\"col-md-3\"\r\n                                v-show=\"form.unit_type_id != 'ZZ'\"\r\n                            >\r\n                                <div\r\n                                    class=\"form-group\"\r\n                                    :class=\"{\r\n                                        'has-danger': errors.date_of_due\r\n                                    }\"\r\n                                >\r\n                                    <label class=\"control-label\"\r\n                                        >Fec. Vencimiento</label\r\n                                    >\r\n                                    <el-date-picker\r\n                                        v-model=\"form.date_of_due\"\r\n                                        type=\"date\"\r\n                                        value-format=\"yyyy-MM-dd\"\r\n                                        :clearable=\"true\"\r\n                                    ></el-date-picker>\r\n                                    <small\r\n                                        class=\"text-danger\"\r\n                                        v-if=\"errors.date_of_due\"\r\n                                        v-text=\"errors.date_of_due[0]\"\r\n                                    ></small>\r\n                                </div>\r\n                            </div>\r\n                            <div\r\n                                class=\"col-md-3\"\r\n                                v-show=\"form.unit_type_id != 'ZZ'\"\r\n                            >\r\n                                <div class=\"form-group\">\r\n                                    <label class=\"control-label\"\r\n                                        >Cantidad Máxima\r\n                                        <el-tooltip\r\n                                            class=\"item\"\r\n                                            effect=\"dark\"\r\n                                            content=\"La cantidad máxima representada en el envase/contenedor\"\r\n                                            placement=\"top\"\r\n                                        >\r\n                                            <i class=\"fa fa-info-circle\"></i>\r\n                                        </el-tooltip>\r\n                                    </label>\r\n                                    <el-input\r\n                                        :disabled=\"\r\n                                            form.item_unit_types.length != 0\r\n                                        \"\r\n                                        v-model=\"form.max_quantity\"\r\n                                    ></el-input>\r\n                                </div>\r\n                            </div>\r\n                            <div class=\"d-flex\" v-if=\"showSeries\">\r\n                                <div class=\"col-md-4\">\r\n                                    <div\r\n                                        v-show=\"form.unit_type_id != 'ZZ'\"\r\n                                        class=\"col-md-3 center-el-checkbox\"\r\n                                    >\r\n                                        <div class=\"form-group\">\r\n                                            <el-checkbox\r\n                                                v-model=\"form.series_enabled\"\r\n                                                @change=\"changeLotsEnabled\"\r\n                                                >¿Maneja series?</el-checkbox\r\n                                            ><br />\r\n                                        </div>\r\n                                    </div>\r\n                                    <div\r\n                                        class=\"col-md-4 d-flex align-items-end\"\r\n                                        v-if=\"\r\n                                            form.unit_type_id != 'ZZ' &&\r\n                                                form.series_enabled\r\n                                        \"\r\n                                    >\r\n                                        <div\r\n                                            class=\"form-group \"\r\n                                            :class=\"{\r\n                                                'has-danger': errors.lot_code\r\n                                            }\"\r\n                                        >\r\n                                            <label class=\"control-label\">\r\n                                                Ingrese series\r\n                                            </label>\r\n\r\n                                            <el-button\r\n                                                style=\"margin-top:2%;margin-left:15px;\"\r\n                                                type=\"primary\"\r\n                                                icon=\"el-icon-edit-outline\"\r\n                                                @click.prevent=\"clickLotcode\"\r\n                                            ></el-button>\r\n\r\n                                            <small\r\n                                                class=\"text-danger\"\r\n                                                v-if=\"errors.lot_code\"\r\n                                                v-text=\"errors.lot_code[0]\"\r\n                                            ></small>\r\n                                        </div>\r\n                                    </div>\r\n                                </div>\r\n                                <div class=\"col-md-4\">\r\n                                    <div\r\n                                        v-show=\"form.unit_type_id != 'ZZ'\"\r\n                                        class=\"col-md-3 center-el-checkbox\"\r\n                                    >\r\n                                        <div class=\"form-group\">\r\n                                            <el-checkbox\r\n                                                v-model=\"form.lots_enabled\"\r\n                                                @change=\"changeLotsEnabled\"\r\n                                                >¿Maneja lotes?</el-checkbox\r\n                                            ><br />\r\n                                        </div>\r\n                                    </div>\r\n\r\n                                    <div\r\n                                        class=\"col-md-6\"\r\n                                        v-show=\"\r\n                                            form.unit_type_id != 'ZZ' &&\r\n                                                form.lots_enabled\r\n                                        \"\r\n                                    >\r\n                                        <div\r\n                                            class=\"form-group\"\r\n                                            :class=\"{\r\n                                                'has-danger': errors.lot_code\r\n                                            }\"\r\n                                        >\r\n                                            <label class=\"control-label\">\r\n                                                Código lote\r\n                                            </label>\r\n                                            <el-input v-model=\"form.lot_code\">\r\n                                                <i\r\n                                                    slot=\"prefix\"\r\n                                                    class=\"el-icon-edit-outline\"\r\n                                                ></i\r\n                                            ></el-input>\r\n                                            <small\r\n                                                class=\"text-danger\"\r\n                                                v-if=\"errors.lot_code\"\r\n                                                v-text=\"errors.lot_code[0]\"\r\n                                            ></small>\r\n                                        </div>\r\n                                    </div>\r\n                                </div>\r\n                            </div>\r\n\r\n                            <!--    <div class=\"col-md-3 center-el-checkbox\" >\r\n                        <div class=\"form-group\"  >\r\n                            <el-checkbox v-model=\"form.has_perception\" @change=\"changeHasPerception\">Incluye percepción</el-checkbox><br>\r\n                        </div>\r\n                    <