ar\"\r\n                                            />\r\n                                            <i\r\n                                                v-else\r\n                                                class=\"el-icon-plus avatar-uploader-icon\"\r\n                                            ></i>\r\n                                        </el-upload>\r\n                                    </div>\r\n                                </div>\r\n\r\n                                <div class=\"col-md-9\">\r\n                                    <div class=\"row\">\r\n                                        <div class=\"col-md-6\">\r\n                                            <div\r\n                                                class=\"form-group\"\r\n                                                :class=\"{\r\n                                                    'has-danger':\r\n                                                        errors.brand_id\r\n                                                }\"\r\n                                            >\r\n                                                <label class=\"control-label\">\r\n                                                    Marca\r\n                                                </label>\r\n\r\n                                                <a\r\n                                                    href=\"#\"\r\n                                                    v-if=\"\r\n                                                        form_brand.add == false\r\n                                                    \"\r\n                                                    class=\"control-label font-weight-bold text-info\"\r\n                                                    @click=\"\r\n                                                        form_brand.add = true\r\n                                                    \"\r\n                                                >\r\n                      