                }else{\r\n\r\n                        let quantity = this.stock - this.lots.length\r\n                        if(quantity > 0){\r\n                            this.addMoreLots(quantity)\r\n                        }\r\n                        // else{\r\n                        //     this.deleteMoreLots(quantity)\r\n                        // }\r\n                    }\r\n\r\n                }\r\n            },\r\n            addMoreLots(number){\r\n\r\n                for (let i = 0; i < number; i++) {\r\n                    this.clickAddLot()\r\n                }\r\n\r\n            },\r\n            deleteMoreLots(number){\r\n\r\n                for (let i = 0; i < number; i++) {\r\n                    this.lots.pop();\r\n                    this.$emit('addRowLot', this.lots);\r\n                }\r\n\r\n            },\r\n            async validateLots(){\r\n\r\n                let error = 0\r\n\r\n                await this.lots.forEach(element => {\r\n                    if(element.series == null){\r\n                        error++\r\n                    }\r\n                });\r\n\r\n                if(error>0)\r\n                    return {success:false, message:'El campo serie es obligatorio'}\r\n\r\n\r\n                return {success:true}\r\n\r\n            },\r\n            async submit(){\r\n\r\n                let val_lots = await this.validateLots()\r\n                if(!val_lots.success)\r\n                    return this.$toast.error(val_lots.message);\r\n\r\n                await this.$emit('addRowLot', this.lots);\r\n                await this.$emit('update:showDialog', false)\r\n\r\n            },\r\n            clickAddLot() {\r\n\r\n                if(!this.recordId){\r\n                    if(this.lots.length >= this.stock)\r\n                        return this.$toast.error('La cantidad de registros es superior al stock o cantidad');\r\n                }\r\n\r\n\r\n                this.lots.push({\r\n                    id: null,\r\n                    item_id: null,\r\n                    series: null,\r\n                    date:  moment().format('YYYY-MM-DD'),\r\n                    state: 'Activo'\r\n\r\n                });\r\n\r\n                this.$emit('addRowLot', this.lots);\r\n            },\r\n\r\n            close() {\r\n                this.$emit('update:showDialog', false)\r\n                this.$emit('addRowLot', this.lots);\r\n            },\r\n            clickCancel(index) {\r\n                this.lots.splice(index, 1);\r\n               // item.deleted = true\r\n                this.$emit('addRowLot', this.lots);\r\n            },\r\n\r\n            async clickCancelSubmit() {\r\n                this.$emit('addRowLot', []);\r\n                await this.$emit('update:showDialog', false)\r\n            },\r\n            close() {\r\n                this.$emit('update:showDialog', false)\r\n            },\r\n        }\r\n    }\r\n</script>\r\n\n\n\n// WEBPACK FOOTER //\n// resources/js/views/items/partials/lots.vue","var render = function() {\n  var _vm = this\n  var _h = _vm.$createElement\n  var _c = _vm._self._c || _h\n  return _c(\n    \"el-dialog\",\n    {\n      attrs: {\n        width: \"65%\",\n        title: _vm.titleDialog,\n        visible: _vm.showDialog,\n        \"close-on-click-modal\": false,\n        \"append-to-body\": \"\",\n        top: \"7vh\"\n      },\n      on: { close: _vm.close, open: _vm.create }\n    },\n    [\n      _c(\n        \"form\",\n        {\n          attrs: { autocomplete: \"off\" },\n          on: {\n            submit: function($event) {\n              $event.preventDefault()\n              return _vm.submit.apply(null, arguments)\n            }\n          }\n        },\n        [\n          _c(\n            \"div\",\n            { staticClass: \"form-body\" },\n            [\n              _c(\n                \"el-tabs\",\n                { attrs: { \"tab-position\": \"top\" } },\n                [\n                  _c(\